export const sentences: PracticeSentence[] = raw.map((item) => ({
  ...item,
  romanized: getPrimaryRomanization(item.reading),
}));

export function pickSentence(previousId?: string): PracticeSentence {
  const candidates = sentences.filter((s) => s.id !== previousId);
  return candidates[Math.floor(Math.random() * candidates.length)] ?? sentences[0];
}
